import React from 'react';
import { Team } from '../types';
import './TeamRanking.css';

interface TeamRankingProps {
    teams: Team[];
}

const TeamRanking: React.FC<TeamRankingProps> = ({ teams }) => {
    const rankedTeams = teams.sort((a, b) => {
        const winLossA = a.wins / (a.wins + a.losses);
        const winLossB = b.wins / (b.wins + b.losses);
        const strengthOfVictoryA = a.strengthOfVictory;
        const strengthOfVictoryB = b.strengthOfVictory;

        if (winLossA !== winLossB) {
            return winLossB - winLossA; // Higher win percentage first
        } else {
            return strengthOfVictoryB - strengthOfVictoryA; // Higher strength of victory next
        }
    });

    return (
        <div className="team-ranking">
            <h2>Team Rankings</h2>
            <table>
                <thead>
                    <tr>
                        <th>Rank</th>
                        <th>Team Number</th>
                        <th>Wins</th>
                        <th>Losses</th>
                        <th>Strength of Victory</th>
                    </tr>
                </thead>
                <tbody>
                    {rankedTeams.map((team, index) => (
                        <tr key={team.teamNumber}>
                            <td>{index + 1}</td>
                            <td>{team.teamNumber}</td>
                            <td>{team.wins}</td>
                            <td>{team.losses}</td>
                            <td>{team.strengthOfVictory}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default TeamRanking;
